// AUTHENTICATION: Verify who the user is
boolean authenticate(String username, String password) {
    User user = database.findByUsername(username);
    if (user == null) return false;
    String hashedInput = hash(password, user.getSalt());
    return hashedInput.equals(user.getPasswordHash());
}

// AUTHORISATION: Check what the user can do
boolean authorise(User user, String action) {
    if (action.equals("DELETE_USER") && !user.getRole().equals("ADMIN")) {
        return false; // Only admins can delete users
    }
    return true;
}

// BOTH must be checked on every request:
// 1. Is the user authenticated? (valid session)
// 2. Is the user authorised? (has permission for this action)

import java.security.SecureRandom;
import java.security.MessageDigest;
import java.util.Base64;

public class PasswordHasher {
    public static byte[] generateSalt() {
        byte[] salt = new byte[16];
        new SecureRandom().nextBytes(salt);
        return salt;
    }

    public static String hash(String password, byte[] salt) {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update(salt);
        byte[] hashed = md.digest(password.getBytes());
        return Base64.getEncoder().encodeToString(hashed);
    }

    // STORE: salt + hash (both needed for verification)
    // VERIFY: hash(input + stored_salt) == stored_hash?
}

