import java.security.SecureRandom;
import java.util.*;

public class SessionManager {
    private Map<String, Session> activeSessions = new HashMap<>();

    public String createSession(String userId, String role) {
        String sessionId = generateSecureId();
        Session s = new Session(userId, role, System.currentTimeMillis());
        activeSessions.put(sessionId, s);
        return sessionId;
        // Set as cookie: Set-Cookie: session=<id>; HttpOnly; Secure; SameSite=Lax
    }

    public Session validateSession(String sessionId) {
        Session s = activeSessions.get(sessionId);
        if (s == null) return null; // Not found
        if (System.currentTimeMillis() - s.created > 3600000) {
            activeSessions.remove(sessionId); // Expired
            return null;
        }
        return s; // Valid
    }

    public void destroySession(String sessionId) {
        activeSessions.remove(sessionId); // Logout
    }
}

