            "VIEW_OWN_PROFILE", "EDIT_OWN_PROFILE"
        )));
    }

    public static boolean hasPermission(String role, String action) {
        Set<String> perms = rolePermissions.get(role);
        return perms != null && perms.contains(action);
    }
}

import java.util.*;

public class BruteForceProtection {
    static Map<String, Integer> failedAttempts = new HashMap<>();
    static Map<String, Long> lockoutUntil = new HashMap<>();
    static final int MAX_ATTEMPTS = 5;
    static final long LOCKOUT_MS = 300000; // 5 minutes

    public static String attemptLogin(String username, String password) {
        // Check lockout
        Long locked = lockoutUntil.get(username);
        if (locked != null && System.currentTimeMillis() < locked) {
            return "LOCKED: Account locked. Try again later.";
        }

        // Verify credentials
        if (verifyPassword(username, password)) {
            failedAttempts.remove(username);
            return "SUCCESS";
        }

        // Track failures
        int fails = failedAttempts.getOrDefault(username, 0) + 1;
        failedAttempts.put(username, fails);
        if (fails >= MAX_ATTEMPTS) {
            lockoutUntil.put(username, System.currentTimeMillis() + LOCKOUT_MS);
            return "LOCKED: Too many attempts. Account locked for 5 minutes.";
        }
        return "FAILED: " + (MAX_ATTEMPTS - fails) + " attempts remaining.";
    }
}

// BAD: Giving everyone admin access
public class UserService {
    // Every user can do everything!
    public void deleteUser(String userId) {
        database.delete(userId); // No permission check
    }
}

// GOOD: Least privilege
public class UserService {
    public void deleteUser(String requesterId, String targetId) {
        User requester = database.findById(requesterId);
        if (!requester.getRole().equals("ADMIN")) {
            throw new SecurityException("Insufficient privileges");
        }
        if (requesterId.equals(targetId)) {
            throw new SecurityException("Cannot delete own account");
        }
        database.delete(targetId);
        auditLog.log(requesterId + " deleted " + targetId);
    }
}

