import java.security.SecureRandom;
import java.util.*;

public class PasswordReset {
    static Map<String, ResetToken> resetTokens = new HashMap<>();

    public static String initiateReset(String email) {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        String token = Base64.getUrlEncoder().encodeToString(bytes);

        resetTokens.put(hashToken(token), new ResetToken(
            email, System.currentTimeMillis() + 3600000 // 1 hour
        ));

        // Send email with: https://app.com/reset?token=<token>
        return token; // Only sent via email, never stored in plain text
    }

    public static boolean completeReset(String token, String newPassword) {
        String hashedToken = hashToken(token);
        ResetToken rt = resetTokens.get(hashedToken);
        if (rt == null) return false; // Invalid token
        if (System.currentTimeMillis() > rt.expiry) return false; // Expired

        // Update password and invalidate token
        updatePassword(rt.email, newPassword);
        resetTokens.remove(hashedToken);
        return true;
    }
}

