public class AuthVsAuthz {
    public static void main(String[] args) {
        System.out.println("=== AUTHENTICATION vs AUTHORISATION ===");
        System.out.println();
        System.out.println("AUTHENTICATION (Who are you?)");
        System.out.println("  Input: username + password");
        System.out.println("  Check: credentials match stored record?");
        System.out.println("  Result: VERIFIED or REJECTED");
        System.out.println("  Analogy: Showing your passport at the border");
        System.out.println();
        System.out.println("AUTHORISATION (What can you do?)");
        System.out.println("  Input: user's role + requested action");
        System.out.println("  Check: does this role have permission?");
        System.out.println("  Result: ALLOWED or DENIED");
        System.out.println("  Analogy: Your security clearance level");
        System.out.println();

        // Demonstrate the two-step check
        String[][] tests = {
            {"alice", "pass123", "ADMIN", "DELETE_USER"},
            {"bob", "pass456", "USER", "DELETE_USER"},
            {"eve", "wrong", "?", "VIEW_PAGE"}
        };

        for (String[] t : tests) {
            System.out.println("User: " + t[0]);
            boolean authn = !t[1].equals("wrong");
            System.out.println("  Authentication: " + (authn ? "PASS" : "FAIL"));
            if (authn) {
                boolean authz = t[2].equals("ADMIN") || !t[3].equals("DELETE_USER");
                System.out.println("  Authorisation for " + t[3] + ": " + (authz ? "ALLOWED" : "DENIED"));
            } else {
                System.out.println("  Authorisation: SKIPPED (not authenticated)");
            }
            System.out.println();
        }
    }
}

import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;

public class SecurePasswordStorage {

    public static byte[] generateSalt() {
        byte[] salt = new byte[16];
        new SecureRandom().nextBytes(salt);
        return salt;
    }

    public static String hashPassword(String password, byte[] salt) throws Exception {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update(salt);
        byte[] hashed = md.digest(password.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(hashed);
    }

    public static void main(String[] args) throws Exception {
        String password = "MySecurePass123!";

        // Registration: generate salt, hash password, store both
        byte[] salt = generateSalt();
        String hash = hashPassword(password, salt);
        String saltB64 = Base64.getEncoder().encodeToString(salt);

        System.out.println("=== REGISTRATION ===");
        System.out.println("Password: " + password);
        System.out.println("Salt (Base64): " + saltB64);
        System.out.println("Hash (Base64): " + hash);
        System.out.println("Store in DB: salt=" + saltB64 + ", hash=" + hash);
        System.out.println();

        // Login: retrieve salt, hash input, compare
        System.out.println("=== LOGIN VERIFICATION ===");
        String loginAttempt = "MySecurePass123!";
        String loginHash = hashPassword(loginAttempt, salt);
        System.out.println("Input: " + loginAttempt);
        System.out.println("Computed hash: " + loginHash);
        System.out.println("Match: " + hash.equals(loginHash));
        System.out.println();

        // Wrong password
        String wrongAttempt = "WrongPassword";
        String wrongHash = hashPassword(wrongAttempt, salt);
        System.out.println("Wrong input: " + wrongAttempt);
        System.out.println("Computed hash: " + wrongHash);
        System.out.println("Match: " + hash.equals(wrongHash));
        System.out.println();

        // Same password, different salt = different hash
        byte[] salt2 = generateSalt();
        String hash2 = hashPassword(password, salt2);
        System.out.println("=== WHY SALT MATTERS ===");
        System.out.println("Same password, salt 1: " + hash);
        System.out.println("Same password, salt 2: " + hash2);
        System.out.println("Different hashes: " + !hash.equals(hash2));
    }
}

import java.util.regex.*;
import java.util.*;

public class HardcodedCredentialDetector {

    static final List<Pattern> PATTERNS = Arrays.asList(
        Pattern.compile("password\\s*=\\s*\"[^\"]+\"", Pattern.CASE_INSENSITIVE),
        Pattern.compile("passwd\\s*=\\s*\"[^\"]+\"", Pattern.CASE_INSENSITIVE),
        Pattern.compile("apiKey\\s*=\\s*\"[^\"]+\"", Pattern.CASE_INSENSITIVE),
        Pattern.compile("secret\\s*=\\s*\"[^\"]+\"", Pattern.CASE_INSENSITIVE),
        Pattern.compile("\\.equals\\(\\s*\"[^\"]+\"\\s*\\)", Pattern.CASE_INSENSITIVE)
    );

    static void scanCode(String filename, String code) {
        System.out.println("Scanning: " + filename);
        String[] lines = code.split("\n");
        boolean found = false;
        for (int i = 0; i < lines.length; i++) {
            for (Pattern p : PATTERNS) {
                Matcher m = p.matcher(lines[i]);
                if (m.find()) {
                    System.out.println("  LINE " + (i+1) + " [CWE-798]: " + lines[i].trim());
                    found = true;
                }
            }
        }
        if (!found) System.out.println("  No hard-coded credentials found.");
        System.out.println();
    }

    public static void main(String[] args) {
        scanCode("LoginService.java",
            "public boolean verify(String pass) {\n" +
            "    if (pass.equals(\"Mew!\")) {\n" +
            "        return true;\n" +
            "    }\n" +
            "    return false;\n" +
            "}");

        scanCode("DatabaseConfig.java",
            "String host = System.getenv(\"DB_HOST\");\n" +
            "String password = \"SuperSecret123\";\n" +
            "String apiKey = \"sk-abc123def456\";\n");

        scanCode("SafeConfig.java",
            "String host = System.getenv(\"DB_HOST\");\n" +
            "String password = System.getenv(\"DB_PASS\");\n" +
            "String apiKey = config.getProperty(\"api.key\");\n");
    }
}

