import java.util.*;

public class RBACSystem {
    static Map<String, Set<String>> rolePermissions = new HashMap<>();
    static Map<String, String> userRoles = new HashMap<>();

    static {
        rolePermissions.put("ADMIN", new HashSet<>(Arrays.asList(
            "VIEW_USERS", "CREATE_USER", "DELETE_USER", "EDIT_USER",
            "VIEW_REPORTS", "EXPORT_REPORTS", "MANAGE_SETTINGS", "VIEW_AUDIT_LOG"
        )));
        rolePermissions.put("MANAGER", new HashSet<>(Arrays.asList(
            "VIEW_USERS", "EDIT_USER", "VIEW_REPORTS", "EXPORT_REPORTS"
        )));
        rolePermissions.put("USER", new HashSet<>(Arrays.asList(
            "VIEW_OWN_PROFILE", "EDIT_OWN_PROFILE", "VIEW_REPORTS"
        )));
        rolePermissions.put("GUEST", new HashSet<>(Arrays.asList(
            "VIEW_PUBLIC_PAGE"
        )));

        userRoles.put("alice", "ADMIN");
        userRoles.put("bob", "MANAGER");
        userRoles.put("charlie", "USER");
        userRoles.put("guest1", "GUEST");
    }

    static boolean checkAccess(String user, String action) {
        String role = userRoles.get(user);
        if (role == null) return false;
        Set<String> perms = rolePermissions.get(role);
        return perms != null && perms.contains(action);
    }

    public static void main(String[] args) {
        String[] users = {"alice", "bob", "charlie", "guest1", "unknown"};
        String[] actions = {"DELETE_USER", "VIEW_REPORTS", "EDIT_OWN_PROFILE", "VIEW_PUBLIC_PAGE"};

        System.out.println("=== RBAC ACCESS MATRIX ===");
        System.out.printf("%-10s", "");
        for (String a : actions) System.out.printf("%-20s", a);
        System.out.println();

        for (String u : users) {
            String role = userRoles.getOrDefault(u, "NONE");
            System.out.printf("%-10s", u + "(" + role.charAt(0) + ")");
            for (String a : actions) {
                System.out.printf("%-20s", checkAccess(u, a) ? "ALLOWED" : "DENIED");
            }
            System.out.println();
        }
    }
}

import java.util.*;

public class BruteForceProtection {
    static Map<String, Integer> failCount = new HashMap<>();
    static Map<String, Long> lockUntil = new HashMap<>();
    static Map<String, String> users = new HashMap<>();
    static final int MAX_FAILS = 3;
    static final long LOCKOUT_MS = 30000; // 30 seconds for demo

    static { users.put("alice", "correctPassword"); }

    static String login(String username, String password) {
        // Check lockout
        Long locked = lockUntil.get(username);
        long now = System.currentTimeMillis();
        if (locked != null && now < locked) {
            long remaining = (locked - now) / 1000;
            return "LOCKED: Try again in " + remaining + " seconds";
        }

        // Verify
        String stored = users.get(username);
        if (stored != null && stored.equals(password)) {
            failCount.remove(username);
            lockUntil.remove(username);
            return "SUCCESS: Welcome " + username;
        }

        // Track failure
        int fails = failCount.getOrDefault(username, 0) + 1;
        failCount.put(username, fails);

        if (fails >= MAX_FAILS) {
            lockUntil.put(username, now + LOCKOUT_MS);
            return "LOCKED: " + fails + " failed attempts. Account locked for 30 seconds.";
        }
        return "FAILED: " + (MAX_FAILS - fails) + " attempts remaining";
    }

    public static void main(String[] args) {
        System.out.println("=== BRUTE FORCE PROTECTION ===");
        System.out.println(login("alice", "wrong1"));
        System.out.println(login("alice", "wrong2"));
        System.out.println(login("alice", "wrong3"));
        System.out.println(login("alice", "correctPassword")); // Locked!
        System.out.println();
        System.out.println("After lockout expires:");
        lockUntil.remove("alice"); failCount.remove("alice");
        System.out.println(login("alice", "correctPassword"));
    }
}

