    static {
        invoices.put("INV-001", Map.of("owner", "alice", "amount", "500", "item", "Laptop"));
        invoices.put("INV-002", Map.of("owner", "bob", "amount", "1200", "item", "Server"));
        invoices.put("INV-003", Map.of("owner", "alice", "amount", "50", "item", "Mouse"));
    }

    // VULNERABLE: No ownership check!
    static String getInvoiceVulnerable(String invoiceId) {
        Map<String, String> inv = invoices.get(invoiceId);
        if (inv == null) return "Not found";
        return "Invoice " + invoiceId + ": " + inv.get("item") + " - $" + inv.get("amount");
    }

    // FIXED: Checks ownership
    static String getInvoiceSecure(String invoiceId, String currentUser) {
        Map<String, String> inv = invoices.get(invoiceId);
        if (inv == null) return "Not found";
        if (!inv.get("owner").equals(currentUser)) {
            return "ACCESS DENIED: This invoice belongs to " + inv.get("owner") + ", not " + currentUser;
        }
        return "Invoice " + invoiceId + ": " + inv.get("item") + " - $" + inv.get("amount");
    }

    public static void main(String[] args) {
        System.out.println("=== IDOR VULNERABILITY ===");
        System.out.println("Alice requests her invoice:");
        System.out.println("  " + getInvoiceVulnerable("INV-001"));
        System.out.println("Alice changes ID to see Bob's invoice:");
        System.out.println("  " + getInvoiceVulnerable("INV-002"));
        System.out.println("  (BUG: Alice can see Bob's data!)\n");

        System.out.println("=== FIXED VERSION ===");
        System.out.println("Alice requests her invoice:");
        System.out.println("  " + getInvoiceSecure("INV-001", "alice"));
        System.out.println("Alice tries Bob's invoice:");
        System.out.println("  " + getInvoiceSecure("INV-002", "alice"));
    }
}

import java.security.SecureRandom;
import java.util.*;

public class SessionLifecycle {
    static Map<String, Map<String, Object>> sessions = new HashMap<>();

    static String createSession(String userId, String role) {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        String sessionId = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);

        Map<String, Object> data = new HashMap<>();
        data.put("userId", userId);
        data.put("role", role);
        data.put("created", System.currentTimeMillis());
        data.put("lastAccess", System.currentTimeMillis());
        sessions.put(sessionId, data);
        return sessionId;
    }

    static Map<String, Object> validateSession(String sessionId) {
        if (sessionId == null) return null;
        Map<String, Object> s = sessions.get(sessionId);
        if (s == null) return null;

        long now = System.currentTimeMillis();
        long created = (Long) s.get("created");
        long lastAccess = (Long) s.get("lastAccess");

        // Absolute timeout: 8 hours
        if (now - created > 28800000) { sessions.remove(sessionId); return null; }
        // Idle timeout: 30 minutes
        if (now - lastAccess > 1800000) { sessions.remove(sessionId); return null; }

        s.put("lastAccess", now);
        return s;
    }

    static void destroySession(String sessionId) {
        sessions.remove(sessionId);
    }

    public static void main(String[] args) {
        System.out.println("=== SESSION LIFECYCLE ===");
        String sid = createSession("alice", "ADMIN");
        System.out.println("Created: " + sid.substring(0, 12) + "...");

        Map<String, Object> s = validateSession(sid);
        System.out.println("Valid: " + (s != null) + " User: " + s.get("userId"));

        System.out.println("Invalid ID: " + (validateSession("fake-id") != null));

        destroySession(sid);
        System.out.println("After logout: " + (validateSession(sid) != null));
        System.out.println("Active sessions: " + sessions.size());
    }
}

import java.security.*;
import java.util.*;

public class SecureLoginFlow {
    static Map<String, String[]> users = new HashMap<>(); // username -> [salt, hash, role]
    static Map<String, Integer> failCounts = new HashMap<>();
    static Map<String, Long> lockouts = new HashMap<>();
    static Map<String, Map<String, String>> sessions = new HashMap<>();

    static String hash(String pass, String salt) throws Exception {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update(Base64.getDecoder().decode(salt));
        return Base64.getEncoder().encodeToString(md.digest(pass.getBytes()));
    }

    static void register(String user, String pass, String role) throws Exception {
        byte[] saltBytes = new byte[16];
        new SecureRandom().nextBytes(saltBytes);
        String salt = Base64.getEncoder().encodeToString(saltBytes);
        String hashed = hash(pass, salt);
        users.put(user, new String[]{salt, hashed, role});
    }

    static String login(String user, String pass) throws Exception {
        // 1. Check lockout
        Long locked = lockouts.get(user);
        if (locked != null && System.currentTimeMillis() < locked)
            return "LOCKED: Account temporarily locked";

        // 2. Find user
        String[] record = users.get(user);

        // 3. Verify (same response for bad user and bad password)
        boolean valid = false;
        if (record != null) {
            String computed = hash(pass, record[0]);
            valid = computed.equals(record[1]);
        }

        if (!valid) {
            int fails = failCounts.getOrDefault(user, 0) + 1;
            failCounts.put(user, fails);
            if (fails >= 5) {
                lockouts.put(user, System.currentTimeMillis() + 300000);
                return "LOCKED: Too many failures";
            }
            return "FAILED: Invalid credentials"; // Generic message!
        }

        // 4. Success: create session
        failCounts.remove(user);
        byte[] sid = new byte[32];
        new SecureRandom().nextBytes(sid);
        String sessionId = Base64.getUrlEncoder().withoutPadding().encodeToString(sid);
        sessions.put(sessionId, Map.of("user", user, "role", record[2]));
        return "SUCCESS: Session=" + sessionId.substring(0, 12) + "...";
    }

    public static void main(String[] args) throws Exception {
        register("alice", "StrongPass!23", "ADMIN");
        register("bob", "BobSecure456", "USER");

        System.out.println("=== SECURE LOGIN FLOW ===");
        System.out.println(login("alice", "StrongPass!23"));
        System.out.println(login("alice", "wrong"));
        System.out.println(login("nonexistent", "pass")); // Same error!
        System.out.println(login("bob", "BobSecure456"));
    }
}

