import java.security.SecureRandom;
import java.util.*;

public class MFADemo {
    static Map<String, String> mfaCodes = new HashMap<>();
    static Map<String, Long> codeExpiry = new HashMap<>();
    static final long CODE_VALIDITY = 300000; // 5 minutes

    static String generateMFACode(String userId) {
        int code = new SecureRandom().nextInt(900000) + 100000;
        String codeStr = String.valueOf(code);
        mfaCodes.put(userId, codeStr);
        codeExpiry.put(userId, System.currentTimeMillis() + CODE_VALIDITY);
        return codeStr;
    }

    static String verifyMFACode(String userId, String inputCode) {
        String stored = mfaCodes.get(userId);
        Long expiry = codeExpiry.get(userId);

        if (stored == null) return "INVALID: No code generated";
        if (System.currentTimeMillis() > expiry) {
            mfaCodes.remove(userId);
            return "EXPIRED: Code has expired. Request new code.";
        }
        if (!stored.equals(inputCode)) return "WRONG: Incorrect code";

        // Valid! Remove code (single use)
        mfaCodes.remove(userId);
        codeExpiry.remove(userId);
        return "VERIFIED: MFA complete";
    }

    public static void main(String[] args) {
        System.out.println("=== MULTI-FACTOR AUTHENTICATION ===");
        System.out.println();

        // Step 1: Password verified, now MFA
        System.out.println("Step 1: Password verified for alice");
        String code = generateMFACode("alice");
        System.out.println("Step 2: MFA code sent to alice's phone: " + code);
        System.out.println();

        System.out.println("Step 3: Alice enters wrong code:");
        System.out.println("  " + verifyMFACode("alice", "000000"));
        System.out.println();

        System.out.println("Step 4: Alice enters correct code:");
        System.out.println("  " + verifyMFACode("alice", code));
        System.out.println();

        System.out.println("Step 5: Replay attack (reuse code):");
        System.out.println("  " + verifyMFACode("alice", code));
    }
}

import java.util.regex.*;

public class PasswordStrength {

    static String[] validatePassword(String password) {
        java.util.List<String> issues = new java.util.ArrayList<>();

        if (password == null || password.length() < 8)
            issues.add("Too short (min 8 characters)");
        if (password != null && password.length() > 64)
            issues.add("Too long (max 64 characters)");
        if (password == null || !password.matches(".*[A-Z].*"))
            issues.add("Missing uppercase letter");
        if (password == null || !password.matches(".*[a-z].*"))
            issues.add("Missing lowercase letter");
        if (password == null || !password.matches(".*[0-9].*"))
            issues.add("Missing digit");
        if (password == null || !password.matches(".*[!@#$%^&*()_+\\-=].*"))
            issues.add("Missing special character");

        // Check common passwords
        String[] common = {"password", "123456", "qwerty", "admin", "letmein"};
        if (password != null) {
            for (String c : common) {
                if (password.toLowerCase().contains(c))
                    issues.add("Contains common password: " + c);
            }
        }

        return issues.toArray(new String[0]);
    }

    public static void main(String[] args) {
        String[] tests = {"password123", "Short1!", "NoSpecial123", "Str0ng!Pass#2024", "admin"};
        for (String p : tests) {
            String[] issues = validatePassword(p);
            System.out.println("Password: \"" + p + "\"");
            if (issues.length == 0) System.out.println("  STRONG");
            else for (String i : issues) System.out.println("  FAIL: " + i);
            System.out.println();
        }
    }
}

import java.time.LocalDateTime;
import java.util.*;

public class AuditLogger {
    static List<String> auditLog = new ArrayList<>();

    static void log(String event, String user, String ip, String result, String detail) {
        String entry = String.format("[%s] %s user=%s ip=%s result=%s detail=%s",
            LocalDateTime.now().toString().substring(0, 19), event, user, ip, result, detail);
        auditLog.add(entry);
        System.out.println(entry);
    }

    static void detectAnomalies() {
        Map<String, Integer> failsByUser = new HashMap<>();
        Map<String, Integer> failsByIP = new HashMap<>();
        for (String entry : auditLog) {
            if (entry.contains("result=FAILED")) {
                String user = entry.replaceAll(".*user=(\\S+).*", "$1");
                String ip = entry.replaceAll(".*ip=(\\S+).*", "$1");
                failsByUser.merge(user, 1, Integer::sum);
                failsByIP.merge(ip, 1, Integer::sum);
            }
        }
        System.out.println("\n=== ANOMALY DETECTION ===");
        failsByUser.forEach((u, c) -> {
            if (c >= 3) System.out.println("ALERT: User '" + u + "' has " + c + " failed logins (brute force?)");
        });
        failsByIP.forEach((ip, c) -> {
            if (c >= 5) System.out.println("ALERT: IP " + ip + " has " + c + " failed logins (credential stuffing?)");
        });
    }

    public static void main(String[] args) {
        System.out.println("=== AUTHENTICATION AUDIT LOG ===");
        log("LOGIN", "alice", "10.0.0.1", "SUCCESS", "normal");
        log("LOGIN", "bob", "45.33.22.1", "FAILED", "wrong_password");
        log("LOGIN", "bob", "45.33.22.1", "FAILED", "wrong_password");
        log("LOGIN", "bob", "45.33.22.1", "FAILED", "wrong_password");
        log("LOGIN", "admin", "45.33.22.1", "FAILED", "wrong_password");
        log("LOGIN", "root", "45.33.22.1", "FAILED", "wrong_password");
        log("ROLE_CHANGE", "alice", "10.0.0.1", "SUCCESS", "bob:USER->ADMIN");
        log("LOGOUT", "alice", "10.0.0.1", "SUCCESS", "normal");
        detectAnomalies();
    }
}

import java.util.*;

public class PrivilegeEscalation {
    static Map<String, String> userRoles = new HashMap<>(Map.of(
        "alice", "ADMIN", "bob", "MANAGER", "charlie", "USER"
    ));

    static final Map<String, Integer> ROLE_LEVELS = Map.of(
        "USER", 1, "MANAGER", 2, "ADMIN", 3
    );

    // VULNERABLE: No check on who is changing roles!
    static String changeRoleVulnerable(String targetUser, String newRole) {
        userRoles.put(targetUser, newRole);
        return "Changed " + targetUser + " to " + newRole;
    }

    // FIXED: Proper privilege checks
    static String changeRoleSecure(String requester, String target, String newRole) {
        String reqRole = userRoles.get(requester);
        if (reqRole == null) return "ERROR: Requester not found";
        if (!"ADMIN".equals(reqRole)) return "DENIED: Only admins can change roles";
        if (requester.equals(target)) return "DENIED: Cannot change own role";

        int newLevel = ROLE_LEVELS.getOrDefault(newRole, 0);
        int reqLevel = ROLE_LEVELS.getOrDefault(reqRole, 0);
        if (newLevel >= reqLevel) return "DENIED: Cannot assign role equal to or above your own";

        String oldRole = userRoles.get(target);
        userRoles.put(target, newRole);
        return "SUCCESS: " + target + " changed from " + oldRole + " to " + newRole + " (by " + requester + ")";
    }

    public static void main(String[] args) {
        System.out.println("=== PRIVILEGE ESCALATION PREVENTION ===");
        System.out.println();
        System.out.println("VULNERABLE:");
        System.out.println("  " + changeRoleVulnerable("charlie", "ADMIN")); // Anyone can become admin!
        userRoles.put("charlie", "USER"); // reset
        System.out.println();
        System.out.println("SECURE:");
        System.out.println("  " + changeRoleSecure("charlie", "charlie", "ADMIN")); // User tries self-promote
        System.out.println("  " + changeRoleSecure("bob", "charlie", "ADMIN")); // Manager tries
        System.out.println("  " + changeRoleSecure("alice", "charlie", "ADMIN")); // Admin tries to make another admin
        System.out.println("  " + changeRoleSecure("alice", "charlie", "MANAGER")); // Admin promotes to manager
        System.out.println("  " + changeRoleSecure("alice", "alice", "USER")); // Admin tries self-demote
    }
}

public class SecurityAssessment {
    static int score = 0;
    static int total = 0;

    static void check(String item, boolean pass) {
        total++;
        String status = pass ? "PASS" : "FAIL";
        if (pass) score++;
        System.out.println("  [" + status + "] " + item);
    }

    public static void main(String[] args) {
        System.out.println("=== AUTHENTICATION & ACCESS CONTROL ASSESSMENT ===");
        System.out.println();

        System.out.println("AUTHENTICATION:");
        check("Passwords hashed with salt (not plain text)", true);
        check("Uses bcrypt/PBKDF2/Argon2 (not MD5/SHA1)", true);
        check("No hard-coded credentials in source", true);
        check("Generic error messages (no user enumeration)", true);
        check("Brute-force protection (lockout/rate limit)", true);
        check("MFA available for sensitive accounts", false);
        check("Secure password reset flow", true);
        check("Password strength requirements enforced", true);
        System.out.println();

        System.out.println("SESSION MANAGEMENT:");
        check("Session IDs cryptographically random", true);
        check("Session expires (absolute timeout)", true);
        check("Session expires (idle timeout)", false);
        check("Session destroyed on logout", true);
        check("New session ID after login (fixation prevention)", true);
        check("Cookie: HttpOnly, Secure, SameSite", true);
        System.out.println();

        System.out.println("ACCESS CONTROL:");
        check("Role-based access control implemented", true);
        check("Authorisation checked on every request", true);
        check("IDOR prevention (ownership checks)", false);
        check("Principle of least privilege", true);
        check("Admin functions protected", true);
        check("Privilege escalation prevented", true);
        System.out.println();

        System.out.println("AUDIT:");
        check("Login attempts logged", true);
        check("Access denials logged", true);
        check("Role changes logged", false);
        check("Passwords never logged", true);
        System.out.println();

        String rating = score >= 20 ? "EXCELLENT" : score >= 16 ? "GOOD" : score >= 12 ? "FAIR" : "POOR";
        System.out.println("SCORE: " + score + "/" + total + " - " + rating);
    }
}

